module top_module(input rst,input clk,input sig,output rise,output fall);reg [1:0] prev_sig; 
 always @(posedge clk or posedge rst) 
  if (rst == 1'b1) 
  prev_sig <= 2'b00; 
  else 
  prev_sig <= {prev_sig[0], sig}; 
 assign rise = prev_sig[0] == 1'b1 && prev_sig[1] == 1'b0 ? 1'b1 : 1'b0; 
 assign fall = prev_sig[0] == 1'b0 && prev_sig[1] == 1'b1 ? 1'b1 : 1'b0; 
 endmodule
